"use client";

import React, { useState, useEffect } from "react";
import {
  LayoutDashboard,
  Package,
  Search,
  ClipboardCheck,
  Bell,
  CheckCircle,
  XCircle,
  Clock,
  AlertCircle,
  Eye,
  ArrowRight,
  ShieldCheck,
  RefreshCw,
} from "lucide-react";

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchDashboardData = async () => {
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("accessToken");
      if (!token) throw new Error("No access token found. Please login.");

      const res = await fetch("http://localhost:5000/admin/dashboard", {
        headers: { Authorization: `Bearer ${token}` },
      });

      const result = await res.json();

      if (!res.ok)
        throw new Error(result.message || "Failed to fetch dashboard data");

      setData(result);
    } catch (err) {
      console.error("Dashboard Fetch Error:", err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
  }, []);

  // 1. Loading State
  if (loading) {
    return (
      <div className="flex h-screen w-full flex-col items-center justify-center bg-[#f8fafc]">
        <div className="relative">
          <div className="h-16 w-16 rounded-full border-4 border-slate-200 border-t-indigo-600 animate-spin"></div>
          <LayoutDashboard
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-600"
            size={20}
          />
        </div>
        <p className="mt-4 font-black uppercase tracking-widest text-xs text-slate-400 animate-pulse">
          Syncing Systems...
        </p>
      </div>
    );
  }

  // 2. Error State
  if (error || !data) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-[#f8fafc] p-6">
        <div className="max-w-md w-full bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl text-center">
          <div className="bg-rose-50 w-16 h-16 rounded-3xl flex items-center justify-center text-rose-500 mx-auto mb-6">
            <AlertCircle size={32} />
          </div>
          <h2 className="text-2xl font-black text-slate-800">
            Connection Failed
          </h2>
          <p className="text-slate-500 mt-2 font-medium">
            {error || "Data structure mismatch"}
          </p>
          <button
            onClick={fetchDashboardData}
            className="mt-8 w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
          >
            <RefreshCw size={16} />
            Try Again
          </button>
        </div>
      </div>
    );
  }

  // 3. Safe Data Destructuring (Providing defaults to avoid "undefined" crashes)
  const {
    stats = {
      totalLost: 0,
      totalFound: 0,
      totalReturned: 0,
      totalClaims: 0,
      pendingVerification: 0,
    },
    recentClaims = [],
    recentActivity = [],
  } = data;

  const getStatusBadge = (status) => {
    const styles = {
      pending: "bg-amber-50 text-amber-700 border-amber-100",
      approved: "bg-emerald-50 text-emerald-700 border-emerald-100",
      rejected: "bg-rose-50 text-rose-700 border-rose-100",
      claimed: "bg-blue-50 text-blue-700 border-blue-100",
    };
    return `px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ${styles[status] || styles.pending}`;
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col">
      {/* Top Header */}
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-30 border-b border-slate-100 px-8 py-4">
        <div className="flex items-center justify-between max-w-[1600px] mx-auto w-full">
          <div className="flex items-center gap-4">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <LayoutDashboard size={20} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-800 tracking-tight">
                Admin Console
              </h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                Live Monitoring
              </p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button className="p-2.5 text-slate-400 hover:bg-slate-50 rounded-full transition-colors relative">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="h-8 w-[1px] bg-slate-100 mx-2"></div>
            <div className="flex items-center gap-3 bg-slate-50 pl-2 pr-4 py-1.5 rounded-full border border-slate-100">
              <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center text-white font-black text-xs shadow-md">
                A
              </div>
              <span className="text-xs font-bold text-slate-600 tracking-wide">
                Administrator
              </span>
            </div>
          </div>
        </div>
      </header>

      <main className="p-8 max-w-[1600px] mx-auto w-full space-y-8">
        {/* Stats Grid - Fixed mapping to your API keys */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
          {[
            {
              label: "Lost Items",
              val: stats.totalLost,
              icon: Package,
              color: "text-rose-600",
              bg: "bg-rose-50",
            },
            {
              label: "Found Items",
              val: stats.totalFound,
              icon: Search,
              color: "text-emerald-600",
              bg: "bg-emerald-50",
            },
            {
              label: "Claimed",
              val: stats.totalReturned,
              icon: CheckCircle,
              color: "text-blue-600",
              bg: "bg-blue-50",
            },
            {
              label: "All Claims",
              val: stats.totalClaims,
              icon: ClipboardCheck,
              color: "text-indigo-600",
              bg: "bg-indigo-50",
            },
            {
              label: "Unverified",
              val: stats.pendingVerification,
              icon: ShieldCheck,
              color: "text-amber-600",
              bg: "bg-amber-50",
            },
          ].map((item, idx) => (
            <div
              key={idx}
              className="bg-white p-7 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300"
            >
              <div
                className={`${item.bg} ${item.color} w-12 h-12 rounded-2xl flex items-center justify-center mb-5`}
              >
                <item.icon size={24} />
              </div>
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
                {item.label}
              </p>
              <h3 className="text-4xl font-black text-slate-800 mt-1">
                {item.val ?? 0}
              </h3>
            </div>
          ))}
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Claims Section */}
          <div className="lg:col-span-2 space-y-5">
            <div className="flex items-center justify-between px-4">
              <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                <div className="w-2 h-5 bg-indigo-600 rounded-full"></div>
                Recent Claim Requests
              </h3>
            </div>

            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50/50 border-b border-slate-100">
                      <th className="p-6 text-[10px] font-black uppercase tracking-widest text-slate-400">
                        Item Details
                      </th>
                      <th className="p-6 text-[10px] font-black uppercase tracking-widest text-slate-400">
                        Claimer
                      </th>
                      <th className="p-6 text-[10px] font-black uppercase tracking-widest text-slate-400">
                        Status
                      </th>
                      <th className="p-6 text-center text-[10px] font-black uppercase tracking-widest text-slate-400">
                        Manage
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {recentClaims.length > 0 ? (
                      recentClaims.map((claim) => (
                        <tr
                          key={claim._id}
                          className="hover:bg-slate-50/50 transition-colors"
                        >
                          <td className="p-6">
                            <span className="font-bold text-slate-700 block">
                              {claim.itemId?.itemName || "Deleted Item"}
                            </span>
                            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                              ID: {claim._id?.slice(-6)}
                            </span>
                          </td>
                          <td className="p-6">
                            <span className="text-sm font-bold text-slate-600 block">
                              {claim.claimedBy?.name || "Anonymous"}
                            </span>
                          </td>
                          <td className="p-6">
                            <span className={getStatusBadge(claim.status)}>
                              {claim.status}
                            </span>
                          </td>
                          <td className="p-6 text-center">
                            <button className="p-2.5 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all inline-flex">
                              <Eye size={18} />
                            </button>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td
                          colSpan="4"
                          className="p-12 text-center text-slate-400 font-medium italic"
                        >
                          No recent claims to display.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          {/* Activity Timeline Section */}
          <div className="space-y-5">
            <h3 className="text-lg font-black text-slate-800 px-4 flex items-center gap-2">
              <div className="w-2 h-5 bg-emerald-500 rounded-full"></div>
              Activity Log
            </h3>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <div className="space-y-8 relative before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-50">
                {recentActivity.length > 0 ? (
                  recentActivity.map((activity, idx) => (
                    <div key={idx} className="flex gap-6 relative group">
                      <div
                        className={`z-10 w-6 h-6 rounded-full border-4 border-white shadow-sm flex-shrink-0 mt-1 transition-transform group-hover:scale-125 ${
                          activity.type === "found"
                            ? "bg-emerald-500"
                            : activity.type === "lost"
                              ? "bg-rose-500"
                              : "bg-indigo-500"
                        }`}
                      ></div>
                      <div className="flex-1">
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-[10px] font-black uppercase tracking-wider text-slate-300">
                            {activity.type}
                          </span>
                          <span className="text-[10px] font-bold text-slate-300 italic">
                            {new Date(activity.createdAt).toLocaleDateString()}
                          </span>
                        </div>
                        <p className="text-sm font-bold text-slate-700 leading-tight group-hover:text-indigo-600 transition-colors">
                          {activity.itemName}
                        </p>
                      </div>
                    </div>
                  ))
                ) : (
                  <p className="text-center text-slate-400 text-sm italic">
                    No recent activity.
                  </p>
                )}
              </div>
              <button className="w-full mt-10 py-4 border-2 border-dashed border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 hover:border-indigo-200 hover:text-indigo-500 hover:bg-indigo-50 transition-all">
                Full System Log
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
